const { PAGE_MEMBERS } = require('../../constants/page');
const {
  normalizePathToExpressRoute,
  normalizePathToPageErrorStatusCode,
} = require('../normalizers');
const { getFilePageMember } = require('./page-member');
const { getCatchAllMetadata } = require('./path-detail');

/**
 * @typedef { object } ClassifiedNavigablePageFilesByPageMember
 * @property { string[] } view
 * @property { string[] } styles
 * @property { string[] } hooks
 *
 * @typedef { {
 *   [route: string]: ClassifiedNavigablePageFilesByPageMember,
 * } } ClassifiedFilesByPageRoute
 *
 * @typedef { object } ClassifiedHttpErrorPageFilesByPageMember
 * @property { string[] } view
 * @property { string[] } styles
 *
 * @typedef { {
 *   [statusError:string]: ClassifiedHttpErrorPageFilesByPageMember,
 * } } ClassifiedFilesByPageStatusError
 */

/**
 * @param { string[] } navigablePageFiles
 * @returns { ClassifiedFilesByPageRoute | {} } Classified files by page route
 *
 * @example
 * const navigablePageFiles = [
 * 'home.ts',
 * 'home.scss'
 * 'home.desktop.ts',
 * 'home.hooks.server.js'
 * 'home.mobile.css',
 * '[id].js'
 * '[id].scss'
 * ];
 * classifyFilesByRoute(navigablePageFiles) => {
 *  home: {
 *    view: ['home.ts', 'home.desktop.ts'],
 *    styles: ['home.scss', 'home.mobile.css'],
 *    hooks: ['home.hooks.server.js'],
 *  },
 *  ':id': {
 *    view: ['[id].js'],
 *    styles: ['[id].scss'],
 *    hooks: [],
 *  },
 * }
 */
const classifyFilesByRoute = (navigablePageFiles) => {
  const filesByRoute = {};

  navigablePageFiles.forEach((pageFile) => {
    const route = normalizePathToExpressRoute(pageFile);
    const filePageMember = getFilePageMember(pageFile);

    if (!filePageMember) {
      return;
    }

    if (!filesByRoute[route]) {
      filesByRoute[route] = {
        [PAGE_MEMBERS.view]: [],
        [PAGE_MEMBERS.styles]: [],
        [PAGE_MEMBERS.hooks]: [],
        catchAllMetadata: getCatchAllMetadata(pageFile, route),
      };
    }

    filesByRoute[route][filePageMember].push(pageFile);
  });

  return filesByRoute;
};

/**
 * @param { string[] } httpErrorPageFiles
 * @returns { ClassifiedFilesByPageStatusError | {} } Classified files by page status error
 *
 * @example
 * const httpErrorPageFiles = [
 * '404.ts',
 * '404.scss'
 * '404.desktop.ts',
 * '404.mobile.css',
 * '5xx/index.js'
 * ];
 * classifyFilesByStatusError(httpErrorPageFiles) => {
 *  404: {
 *    view: ['404.ts', '404.desktop.ts'],
 *    styles: ['404.scss', '404.mobile.css'],
 *  },
 *  5xx: {
 *    view: ['5xx/index.js'],
 *    styles: [],
 *  },
 * }
 */
const classifyFilesByStatusError = (httpErrorPageFiles) => {
  const filesByStatusError = {};

  httpErrorPageFiles.forEach((pageFile) => {
    const statusError = normalizePathToPageErrorStatusCode(pageFile);
    const filePageMember = getFilePageMember(pageFile);

    if (!filePageMember) {
      return;
    }

    if (!filesByStatusError[statusError]) {
      filesByStatusError[statusError] = {
        [PAGE_MEMBERS.view]: [],
        [PAGE_MEMBERS.styles]: [],
      };
    }

    filesByStatusError[statusError][filePageMember].push(pageFile);
  });

  return filesByStatusError;
};

module.exports = {
  classifyFilesByRoute,
  classifyFilesByStatusError,
};
